export type OpportunityStage =
  | 'Prospecting'
  | 'Qualification'
  | 'Proposal'
  | 'Negotiation'
  | 'ClosedWon'
  | 'ClosedLost';

export type TaskStatus = 'Open' | 'Done';

export type LeadStatus = 'New' | 'Working' | 'Qualified' | 'Unqualified';

export interface Account {
  id: string;
  name: string;
  industry: string;
  website?: string;
  phone?: string;
  createdAt?: string;
  updatedAt?: string;
  contacts?: Contact[];
  opportunities?: Opportunity[];
}

export interface Contact {
  id: string;
  name: string;
  email: string;
  phone?: string;
  accountId: string;
  accountName?: string;
  createdAt?: string;
  updatedAt?: string;
}

export interface Opportunity {
  id: string;
  name: string;
  amount: number;
  stage: OpportunityStage;
  closeDate?: string;
  accountId: string;
  accountName?: string;
  createdAt?: string;
  updatedAt?: string;
}

export interface Lead {
  id: string;
  name: string;
  email?: string;
  company?: string;
  status: LeadStatus;
  source?: string;
  createdAt?: string;
  updatedAt?: string;
}

export interface Task {
  id: string;
  title: string;
  dueDate?: string;
  status: TaskStatus;
  notes?: string;
  createdAt?: string;
  updatedAt?: string;
}

export interface DashboardSummary {
  accounts: number;
  contacts: number;
  openOpportunities: number;
  upcomingTasks: number;
  upcomingTaskList: Task[];
}

export const OPPORTUNITY_STAGES: { key: OpportunityStage; label: string; accent: string }[] = [
  { key: 'Prospecting', label: 'Prospecting', accent: 'var(--stage-prospecting)' },
  { key: 'Qualification', label: 'Qualification', accent: 'var(--stage-qualification)' },
  { key: 'Proposal', label: 'Proposal', accent: 'var(--stage-proposal)' },
  { key: 'Negotiation', label: 'Negotiation', accent: 'var(--stage-negotiation)' },
  { key: 'ClosedWon', label: 'Closed Won', accent: 'var(--stage-won)' },
  { key: 'ClosedLost', label: 'Closed Lost', accent: 'var(--stage-lost)' },
];
